/* eslint-disable require-jsdoc */
import React from 'react';
import './App.css';
import * as _ from 'lodash';

import {User} from 'firebase/auth';

import {auth} from './firebase/firebase.util';

import {Letter, LowercaseLetters, UppercaseLetters} from './data/alphabet';
import {GameLetterTile} from './components/game-tile';
import {HashRouter} from 'react-router-dom';

interface AppState {
  currentUser?: User | null;
  index: number;
  answer?: string | null;
  totalClicks: number;
  rightClicks: number;
}

interface Option {
    id: number;
    name: string;
}

const allLetters = [...UppercaseLetters, ...LowercaseLetters];


class App extends React.Component<{}, AppState> {
    constructor(props: {}) {
        super(props);

        this.state = {
            currentUser: null,
            index: _.random(allLetters.length - 1),
            totalClicks: 0,
            rightClicks: 0,
        };
    }

    componentDidMount() {
        auth.onAuthStateChanged((user: any) => {
            this.setState({
                currentUser: user,
            });
        });
    }

    render() {
        const {index, answer, totalClicks, rightClicks} = this.state;

        const letter: Letter = allLetters[index];

        const otherLetters = [
            this.getAnother(letter.id, letter.capital),
            this.getAnother(letter.id, letter.capital)];

        const options: Array<Option> = [letter, ...otherLetters]
            .map((l: Letter) => ({id: l.id, name: l.pronunciation}));

        return (
            <HashRouter>
                <div className="App">
                    <div className='letters'>
                        <GameLetterTile
                            letter={letter}
                            style='serif'
                        />
                    </div>
                    {answer && <div><h3>{answer}</h3></div>}
                    <div>
                        {_.shuffle(options)
                            .map((o: Option) => {
                                return <button
                                    disabled={!!answer}
                                    className='button'
                                    key={o.id}
                                    onClick={() => this.checkOption(o.id)}>
                                    {o.name}
                                </button>;
                            },
                            )}
                    </div>
                    <div>
                        <button
                            disabled={!answer}
                            className='button'
                            onClick={this.changeIndex}>Next</button>
                    </div>
                    <div>
                        <h2>{rightClicks} for {totalClicks}</h2>
                    </div>
                </div>
            </HashRouter>
        );
    }

    private checkOption = (selected: number) => {
        const {index, totalClicks, rightClicks} = this.state;
        if (selected === index) {
            this.setState({
                answer: 'OK',
                totalClicks: totalClicks + 1,
                rightClicks: rightClicks + 1,
            });
        } else {
            const letter: Letter = allLetters[index];
            this.setState({
                answer: `No, it's ${letter.pronunciation}`,
                totalClicks: totalClicks + 1,
            });
        }
    };

    private changeIndex = () => {
        const newIndex = _.random(allLetters.length - 1);
        this.setState({
            index: newIndex,
            answer: null,
        });
    };

    private getAnother = (id: number, isCapital: boolean): Letter => {
        const list = isCapital ? UppercaseLetters : LowercaseLetters;
        let anotherIndex: number = _.random(list.length - 1);
        while (list[anotherIndex].id === id) {
            anotherIndex = _.random(list.length - 1);
        }
        return list[anotherIndex];
    };
}

export default App;
